/// Annotations for expressing OS-level API availability constraints on native
/// interop bindings generated by `ffigen`.
///
/// These annotations are applied by `ffigen` to generated Dart methods and
/// classes when the corresponding Objective-C/C declaration carries Apple
/// availability macros such as `API_AVAILABLE`, `API_DEPRECATED`, or
/// `API_UNAVAILABLE`.
///
/// Example — generated by ffigen for an ObjC method marked
/// `API_AVAILABLE(ios(14.0)) API_DEPRECATED("use bar", macos(10.14, 12.0))`:
///
/// ```dart
/// @ExternalVersions({
///   'ios': ExternalVersion(min: '14.0'),
///   'macos': ExternalVersion(min: '10.14', max: '12.0',
///       deprecationMessage: 'use bar'),
/// })
/// external void foo();
/// ```
///
/// The `native_api_lint` analyzer plugin reads these annotations and compares
/// them against the Flutter project's minimum deployment target to emit
/// lint warnings at call sites.
library native_interop_annotation;

/// Describes the availability range of a native API on a single OS platform.
///
/// Version strings follow the platform-native format (e.g. `'14.0'`, `'13'`).
class ExternalVersion {
  /// The inclusive minimum OS version on which this API became available.
  ///
  /// `null` if the API was available since the platform's first release (or
  /// the information was not present in the header).
  final String? min;

  /// The exclusive maximum OS version beyond which this API is no longer
  /// available (i.e., it was removed / obsoleted).
  ///
  /// `null` if the API is still available in the latest release.
  final String? max;

  /// An optional human-readable deprecation message, mirroring the string
  /// from the `API_DEPRECATED("message", ...)` macro.
  ///
  /// `null` if the API is not deprecated (only introduced/removed).
  final String? deprecationMessage;

  const ExternalVersion({this.min, this.max, this.deprecationMessage});
}

/// Applied by `ffigen` to generated Dart declarations (methods, functions,
/// classes) that have OS-level API availability constraints from Apple's
/// availability macros.
///
/// The [platforms] map uses lowercase platform identifiers as keys:
/// `'ios'`, `'macos'`, `'tvos'`, `'watchos'`, `'visionos'`.
///
/// The `native_api_lint` analyzer plugin compares these constraints against
/// the project's minimum deployment target to produce lint diagnostics.
///
/// **Do not** apply this annotation manually to handwritten code.
/// It is intended to be emitted by code-generation tools only.
///
/// See also:
/// - [ExternalVersion] — the per-platform version range.
/// - `package:native_api_lint` — the analyzer plugin that processes this
///   annotation.
class ExternalVersions {
  /// Platform-keyed availability metadata.
  ///
  /// Keys are lowercase platform identifiers: `'ios'`, `'macos'`, `'tvos'`,
  /// `'watchos'`, `'visionos'`.
  final Map<String, ExternalVersion> platforms;

  const ExternalVersions(this.platforms);
}
